package com.example.enterpriseapp.service;

import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.repository.AppUserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.util.List;

@Service
@Transactional
public class UserService {

    private final AppUserRepository appUserRepository;

    public UserService(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    public AppUser createUser(AppUser user) {
        if (appUserRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (appUserRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        return appUserRepository.save(user);
    }

    @Transactional(readOnly = true)
    public AppUser getUser(Long id) {
        return appUserRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @Transactional(readOnly = true)
    public List<AppUser> getAllUsers() {
        return appUserRepository.findAll();
    }

    public AppUser updateUser(Long id, AppUser input) {
        AppUser existing = getUser(id);
        existing.setUsername(input.getUsername());
        existing.setEmail(input.getEmail());
        existing.setPasswordHash(input.getPasswordHash());
        existing.setEnabled(input.isEnabled());
        return appUserRepository.save(existing);
    }

    public void deleteUser(Long id) {
        appUserRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.service;

import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.domain.FinancialTransaction;
import com.example.enterpriseapp.repository.AppUserRepository;
import com.example.enterpriseapp.repository.FinancialTransactionRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.math.BigDecimal;
import java.util.List;

@Service
@Transactional
public class TransactionService {

    private final FinancialTransactionRepository financialTransactionRepository;
    private final AppUserRepository appUserRepository;

    public TransactionService(FinancialTransactionRepository financialTransactionRepository, AppUserRepository appUserRepository) {
        this.financialTransactionRepository = financialTransactionRepository;
        this.appUserRepository = appUserRepository;
    }

    public FinancialTransaction createTransaction(Long userId, BigDecimal amount, String currency, String description) {
        AppUser user = appUserRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        FinancialTransaction transaction = new FinancialTransaction();
        transaction.setUser(user);
        transaction.setAmount(amount);
        transaction.setCurrency(currency);
        transaction.setStatus("PENDING");
        transaction.setDescription(description);
        return financialTransactionRepository.save(transaction);
    }

    public FinancialTransaction completeTransaction(Long transactionId) {
        FinancialTransaction transaction = financialTransactionRepository.findById(transactionId)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        transaction.setStatus("COMPLETED");
        return financialTransactionRepository.save(transaction);
    }

    public FinancialTransaction failTransaction(Long transactionId) {
        FinancialTransaction transaction = financialTransactionRepository.findById(transactionId)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        transaction.setStatus("FAILED");
        return financialTransactionRepository.save(transaction);
    }

    @Transactional(readOnly = true)
    public List<FinancialTransaction> getTransactionsForUser(Long userId) {
        return financialTransactionRepository.findByUserId(userId);
    }

    @Transactional(readOnly = true)
    public List<FinancialTransaction> getTransactionsByStatus(String status) {
        return financialTransactionRepository.findByStatus(status);
    }
}

package com.example.enterpriseapp.controller;

import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.service.UserService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    public ResponseEntity<AppUser> createUser(@RequestBody AppUser user) {
        return ResponseEntity.ok(userService.createUser(user));
    }

    @GetMapping("/{id}")
    public ResponseEntity<AppUser> getUser(@PathVariable Long id) {
        return ResponseEntity.ok(userService.getUser(id));
    }

    @GetMapping
    public ResponseEntity<List<AppUser>> getAllUsers() {
        return ResponseEntity.ok(userService.getAllUsers());
    }

    @PutMapping("/{id}")
    public ResponseEntity<AppUser> updateUser(@PathVariable Long id, @RequestBody AppUser user) {
        return ResponseEntity.ok(userService.updateUser(id, user));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteUser(@PathVariable Long id) {
        userService.deleteUser(id);
        return ResponseEntity.noContent().build();
    }
}

package com.example.enterpriseapp.controller;

import com.example.enterpriseapp.domain.FinancialTransaction;
import com.example.enterpriseapp.service.TransactionService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.math.BigDecimal;
import java.util.List;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping("/users/{userId}")
    public ResponseEntity<FinancialTransaction> createTransaction(
            @PathVariable Long userId,
            @RequestParam BigDecimal amount,
            @RequestParam String currency,
            @RequestParam(required = false) String description) {
        return ResponseEntity.ok(transactionService.createTransaction(userId, amount, currency, description));
    }

    @PostMapping("/{transactionId}/complete")
    public ResponseEntity<FinancialTransaction> completeTransaction(@PathVariable Long transactionId) {
        return ResponseEntity.ok(transactionService.completeTransaction(transactionId));
    }

    @PostMapping("/{transactionId}/fail")
    public ResponseEntity<FinancialTransaction> failTransaction(@PathVariable Long transactionId) {
        return ResponseEntity.ok(transactionService.failTransaction(transactionId));
    }

    @GetMapping("/users/{userId}")
    public ResponseEntity<List<FinancialTransaction>> getTransactionsForUser(@PathVariable Long userId) {
        return ResponseEntity.ok(transactionService.getTransactionsForUser(userId));
    }

    @GetMapping
    public ResponseEntity<List<FinancialTransaction>> getTransactionsByStatus(@RequestParam String status) {
        return ResponseEntity.ok(transactionService.getTransactionsByStatus(status));
    }
}

